import re
from typing import List, Dict, Any, Optional

def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    """Execute a safe SELECT-only SQL query on in-memory data."""

    # Normalize query
    query = query.strip()

    # Security checks
    if not _is_safe_query(query):
        raise ValueError("Unsafe SQL query detected")

    # Parse the query
    parsed = _parse_select_query(query)

    # Get available columns from rows
    available_columns = set()
    if rows:
        available_columns = set(rows[0].keys())

    # Validate columns exist
    _validate_columns(parsed, available_columns)

    # Execute the query
    result = rows[:]

    # Apply WHERE clause
    if parsed['where']:
        result = _apply_where_filter(result, parsed['where'])

    # Apply column selection
    if parsed['columns'] != ['*']:
        result = _select_columns(result, parsed['columns'])

    # Apply LIMIT
    if parsed['limit'] is not None:
        result = result[:parsed['limit']]

    return result

def _is_safe_query(query: str) -> bool:
    """Check if query contains only safe SELECT operations."""
    query_upper = query.upper()

    # Check for forbidden keywords
    forbidden = ['DELETE', 'UPDATE', 'INSERT', 'DROP', 'ALTER', 'CREATE', 'PRAGMA']
    for keyword in forbidden:
        if keyword in query_upper:
            return False

    # Check for semicolons (no multi-statement)
    if ';' in query:
        return False

    # Must start with SELECT
    if not query_upper.strip().startswith('SELECT'):
        return False

    return True

def _parse_select_query(query: str) -> dict:
    """Parse a SELECT query into components."""
    query = query.strip()

    # Use regex to parse the query structure
    pattern = r'SELECT\s+(.*?)\s+FROM\s+rows(?:\s+WHERE\s+(.*?))?(?:\s+LIMIT\s+(\d+))?$'
    match = re.match(pattern, query, re.IGNORECASE | re.DOTALL)

    if not match:
        raise ValueError("Invalid SELECT query format")

    columns_str, where_str, limit_str = match.groups()

    # Parse columns
    if columns_str.strip() == '*':
        columns = ['*']
    else:
        columns = [col.strip() for col in columns_str.split(',')]

    # Parse WHERE clause
    where_clause = None
    if where_str:
        where_clause = _parse_where_clause(where_str.strip())

    # Parse LIMIT
    limit = None
    if limit_str:
        limit = int(limit_str)

    return {
        'columns': columns,
        'where': where_clause,
        'limit': limit
    }

def _parse_where_clause(where_str: str) -> dict:
    """Parse WHERE clause into column, operator, and value."""
    # Support operators: =, !=, <, >, <=, >=
    pattern = r'(\w+)\s*(=|!=|<=|>=|<|>)\s*(-?\d+)'
    match = re.match(pattern, where_str)

    if not match:
        raise ValueError("Invalid WHERE clause format")

    column, operator, value = match.groups()

    return {
        'column': column,
        'operator': operator,
        'value': int(value)
    }

def _validate_columns(parsed: dict, available_columns: set) -> None:
    """Validate that all referenced columns exist."""
    columns_to_check = set()

    # Check SELECT columns
    if parsed['columns'] != ['*']:
        columns_to_check.update(parsed['columns'])

    # Check WHERE column
    if parsed['where']:
        columns_to_check.add(parsed['where']['column'])

    # Validate all columns exist
    for column in columns_to_check:
        if column not in available_columns:
            raise ValueError(f"Unknown column: {column}")

def _apply_where_filter(rows: list[dict[str, int]], where_clause: dict) -> list[dict[str, int]]:
    """Apply WHERE clause filtering."""
    column = where_clause['column']
    operator = where_clause['operator']
    value = where_clause['value']

    filtered_rows = []

    for row in rows:
        row_value = row.get(column)
        if row_value is None:
            continue

        if _evaluate_condition(row_value, operator, value):
            filtered_rows.append(row)

    return filtered_rows

def _evaluate_condition(row_value: int, operator: str, target_value: int) -> bool:
    """Evaluate a single WHERE condition."""
    if operator == '=':
        return row_value == target_value
    elif operator == '!=':
        return row_value != target_value
    elif operator == '<':
        return row_value < target_value
    elif operator == '>':
        return row_value > target_value
    elif operator == '<=':
        return row_value <= target_value
    elif operator == '>=':
        return row_value >= target_value
    else:
        raise ValueError(f"Unsupported operator: {operator}")

def _select_columns(rows: list[dict[str, int]], columns: list[str]) -> list[dict[str, int]]:
    """Select only specified columns from rows."""
    selected_rows = []

    for row in rows:
        selected_row = {}
        for column in columns:
            if column in row:
                selected_row[column] = row[column]
        selected_rows.append(selected_row)

    return selected_rows

