def bounded_evaluate(expression: str, variables: dict[str, int], max_nodes: int = 32) -> int:
    def parse_expression(expr):
        # Simple recursive descent parser
        tokens = tokenize(expr)
        pos = [0]  # Use list to allow modification in nested functions

        def peek():
            return tokens[pos[0]] if pos[0] < len(tokens) else None

        def consume():
            token = tokens[pos[0]] if pos[0] < len(tokens) else None
            pos[0] += 1
            return token

        def parse_expr():
            left = parse_term()
            while peek() in ['+', '-']:
                op = consume()
                right = parse_term()
                left = ('binop', op, left, right)
            return left

        def parse_term():
            left = parse_factor()
            while peek() in ['*', '//']:
                op = consume()
                right = parse_factor()
                left = ('binop', op, left, right)
            return left

        def parse_factor():
            token = peek()
            if token == '-':
                consume()
                operand = parse_factor()
                return ('unary', '-', operand)
            elif token == '(':
                consume()
                expr = parse_expr()
                if consume() != ')':
                    raise ValueError("Missing closing parenthesis")
                return expr
            elif token and (token.isdigit() or (token.startswith('-') and token[1:].isdigit())):
                return ('num', int(consume()))
            elif token and token.isidentifier():
                return ('var', consume())
            else:
                raise ValueError(f"Unexpected token: {token}")

        return parse_expr()

    def tokenize(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isspace():
                i += 1
            elif expr[i] in '+-*()':
                tokens.append(expr[i])
                i += 1
            elif expr[i:i+2] == '//':
                tokens.append('//')
                i += 2
            elif expr[i].isdigit():
                j = i
                while j < len(expr) and expr[j].isdigit():
                    j += 1
                tokens.append(expr[i:j])
                i = j
            elif expr[i].isalpha() or expr[i] == '_':
                j = i
                while j < len(expr) and (expr[j].isalnum() or expr[j] == '_'):
                    j += 1
                tokens.append(expr[i:j])
                i = j
            else:
                raise ValueError(f"Invalid character: {expr[i]}")
        return tokens

    def count_nodes(ast):
        if ast[0] == 'num':
            return 1
        elif ast[0] == 'var':
            return 1
        elif ast[0] == 'unary':
            return 1 + count_nodes(ast[2])
        elif ast[0] == 'binop':
            return 1 + count_nodes(ast[2]) + count_nodes(ast[3])
        else:
            raise ValueError(f"Unknown AST node type: {ast[0]}")

    def evaluate_ast(ast):
        if ast[0] == 'num':
            return ast[1]
        elif ast[0] == 'var':
            var_name = ast[1]
            if var_name not in variables:
                raise ValueError(f"Unknown variable: {var_name}")
            return variables[var_name]
        elif ast[0] == 'unary':
            op, operand = ast[1], ast[2]
            if op == '-':
                return -evaluate_ast(operand)
            else:
                raise ValueError(f"Unknown unary operator: {op}")
        elif ast[0] == 'binop':
            op, left, right = ast[1], ast[2], ast[3]
            left_val = evaluate_ast(left)
            right_val = evaluate_ast(right)
            if op == '+':
                return left_val + right_val
            elif op == '-':
                return left_val - right_val
            elif op == '*':
                return left_val * right_val
            elif op == '//':
                if right_val == 0:
                    raise ValueError("Division by zero")
                return left_val // right_val
            else:
                raise ValueError(f"Unknown binary operator: {op}")
        else:
            raise ValueError(f"Unknown AST node type: {ast[0]}")

    # Parse the expression
    ast = parse_expression(expression)

    # Check node count
    if count_nodes(ast) > max_nodes:
